    private readonly List<string> accentClasses =
    [
        "border-primary",
        "border-secondary",
        "border-tertiary",
        "border-outline"
    ];

    private readonly List<string> avatarClasses =
    [
        "bg-blue-50 text-primary",
        "bg-slate-50 text-slate-500",
        "bg-orange-100 text-orange-700",
        "bg-green-100 text-green-700"
    ];

    private List<UserCardModel> users = [];
    private UserFormModel newUser = new();
    private string searchText = string.Empty;
    private bool isLoading;
    private bool isSubmitting;
    private string? loadError;

    private List<UserCardModel> FilteredUsers =>
        users
            .Where(user =>
                string.IsNullOrWhiteSpace(searchText) ||
                user.FullName.Contains(searchText, StringComparison.OrdinalIgnoreCase) ||
                user.Email.Contains(searchText, StringComparison.OrdinalIgnoreCase) ||
                user.Role.Contains(searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    protected override async Task OnInitializedAsync()
    {
        await LoadUsersAsync();
    }

    private async Task LoadUsersAsync()
    {
        isLoading = true;
        loadError = null;

        try
        {
            users = await GetUsersAsync();
        }
        catch
        {
            loadError = "Unable to load users from the API right now. Sample data is shown until the endpoint is ready.";
            users = GetSampleUsers();
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task<List<UserCardModel>> GetUsersAsync()
    {
        var response = await Http.GetAsync("http://localhost:5000/api/UsersApi/GetAllUsers");
        response.EnsureSuccessStatusCode();

        var apiUsers = await response.Content.ReadFromJsonAsync<List<UserDTO>>();

        return apiUsers is { Count: > 0 }
            ? apiUsers.Select(MapToCardModel).ToList()
            : GetSampleUsers();
    }

    private async Task HandleAddUserAsync()
    {
        if (isSubmitting || string.IsNullOrWhiteSpace(newUser.FirstName) || string.IsNullOrWhiteSpace(newUser.LastName))
        {
            return;
        }

        isSubmitting = true;

        try
        {
            await Task.CompletedTask;
            users.Insert(0, CreateCardFromForm(newUser));
            newUser = new UserFormModel();
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private Task HandleDeleteUserAsync(int userId)
    {
        var user = users.FirstOrDefault(item => item.Id == userId);

        if (user is not null)
        {
            users.Remove(user);
        }

        return Task.CompletedTask;
    }

    private UserCardModel MapToCardModel(UserDTO user)
    {
        var paletteIndex = Math.Abs(user.Id) % accentClasses.Count;

        return new UserCardModel
        {
            Id = user.Id,
            FullName = string.IsNullOrWhiteSpace(user.PersonFullName) ? user.UserName : user.PersonFullName,
            Email = BuildEmail(user),
            Role = string.IsNullOrWhiteSpace(user.CreatedByUserName) ? "System User" : $"Created by {user.CreatedByUserName}",
            AccentClass = accentClasses[paletteIndex],
            AvatarClass = avatarClasses[paletteIndex]
        };
    }

    private UserCardModel CreateCardFromForm(UserFormModel form)
    {
        var nextId = users.Count == 0 ? 1 : users.Max(user => user.Id) + 1;
        var paletteIndex = nextId % accentClasses.Count;
        var fullName = $"{form.FirstName} {form.LastName}".Trim();

        return new UserCardModel
        {
            Id = nextId,
            FullName = fullName,
            Email = string.IsNullOrWhiteSpace(form.Email) ? $"{BuildUserName(form)}@example.com" : form.Email,
            Role = "Pending API sync",
            AccentClass = accentClasses[paletteIndex],
            AvatarClass = avatarClasses[paletteIndex]
        };
    }

    private List<UserCardModel> GetSampleUsers() =>
    [
        new UserCardModel
        {
            Id = 1,
            FullName = "Sara Almansour",
            Email = "sara.m@aeon.com",
            Role = "Finance Admin",
            AccentClass = accentClasses[0],
            AvatarClass = avatarClasses[0]
        },
        new UserCardModel
        {
            Id = 2,
            FullName = "Khaled Alotaibi",
            Email = "k.otaibi@aeon.com",
            Role = "Technical Admin",
            AccentClass = accentClasses[1],
            AvatarClass = avatarClasses[1]
        }
    ];

    private static string BuildEmail(UserDTO user)
    {
        if (user.UserName.Contains('@'))
        {
            return user.UserName;
        }

        return $"{user.UserName}@example.com";
    }

    private static string BuildUserName(UserFormModel form) =>
        $"{form.FirstName}.{form.LastName}"
            .Trim('.')
            .Replace(" ", string.Empty)
            .ToLowerInvariant();

    private sealed class UserFormModel
    {
        public string FirstName { get; set; } = string.Empty;
        public string LastName { get; set; } = string.Empty;
        public DateTime? BirthDate { get; set; }
        public string Email { get; set; } = string.Empty;
        public string Password { get; set; } = string.Empty;
        public string PhoneNumber { get; set; } = string.Empty;
    }

